steps.command:
set -euo pipefail
ROOT="{input.outputRoot}"
uv run python - <<'PY'
import csv, glob, json
from pathlib import Path
root = Path("{input.outputRoot}")
log = root / 'logs' / 'inspect.log'
required = [Path('scripts/verify_paralellogram_ip.py'), Path('scripts/verify_paralellogram_ip_rect.py'), Path('scripts/verify_parallelogram_heuristic.py')]
missing = [str(p) for p in required if not p.exists()]
if missing:
    raise SystemExit('missing required verifier scripts: ' + ', '.join(missing))

def read_best_csv(path):
    rows = []
    if not Path(path).exists():
        return rows
    try:
        with open(path, newline='') as f:
            for row in csv.DictReader(f):
                pct = row.get('fraction_fixed_to_5 (%)') or row.get('score') or row.get('screen_pct')
                try:
                    pctv = float(pct) if pct not in (None, '') else None
                except Exception:
                    pctv = None
                rows.append(dict(path=str(path), row=row, pct=pctv))
    except Exception as exc:
        rows.append(dict(path=str(path), error=repr(exc), pct=None))
    return rows

def add_pair(seeds, run_id, ckpt, cfg, source, pct=None):
    if not ckpt or not cfg:
        return
    cp = Path(ckpt); cf = Path(cfg)
    if cp.exists() and cf.exists():
        seeds.append(dict(run_id=str(run_id or cp.parent.name), checkpoint_path=str(cp), config_json=str(cf), source=str(source), known_pct=pct))

seeds = []
for cfg in glob.glob('**/pipeline_config.json', recursive=True) + glob.glob('**/hparams.json', recursive=True):
    p = Path(cfg)
    if '.venv' in p.parts:
        continue
    ckpt = p.with_name('trained_model.pt')
    if ckpt.exists():
        pct = None
        vc = p.parent.parent / 'verification' / 'verified_paralellograms_ip.csv'
        for item in read_best_csv(vc):
            if item.get('pct') is not None:
                pct = item['pct'] if pct is None else min(pct, item['pct'])
        add_pair(seeds, p.parent.name, ckpt, p, 'co-located-config-checkpoint', pct)
for csv_path in ['slurm/batched32_hparam_1247042_top10.csv', '.workflow_runs/parallelogram-improvement-search/global_results.csv']:
    if not Path(csv_path).exists():
        continue
    with open(csv_path, newline='') as f:
        for row in csv.DictReader(f):
            add_pair(seeds, row.get('run_id'), row.get('checkpoint_path'), row.get('config_json'), csv_path, row.get('screen_pct'))
if Path('slurm/top_rect_2048_candidates.csv').exists():
    with open('slurm/top_rect_2048_candidates.csv', newline='') as f:
        for row in csv.DictReader(f):
            rd = row.get('run_dir')
            if rd:
                add_pair(seeds, row.get('run_id'), str(Path(rd) / 'trained_model.pt'), str(Path(rd) / 'pipeline_config.json'), 'slurm/top_rect_2048_candidates.csv', row.get('score'))
uniq = dict()
for s in seeds:
    key = (s['checkpoint_path'], s['config_json'])
    old = uniq.get(key)
    if old is None or (s.get('known_pct') is not None and (old.get('known_pct') is None or float(s['known_pct']) < float(old['known_pct']))):
        uniq[key] = s
seeds = sorted(uniq.values(), key=lambda s: (float(s['known_pct']) if s.get('known_pct') is not None else 999.0, s['run_id']))
if not seeds:
    raise SystemExit('no existing checkpoint/config seed pairs found')
results = []
for p in ['constructions/best_m018_2048/verification/verified_paralellograms_ip.csv', '.workflow_runs/parallelogram-improvement-search/global_results.csv', 'slurm/top_rect_2048_candidates.csv']:
    results.extend(read_best_csv(p))
valid_results = [r for r in results if r.get('pct') is not None]
best_result = min(valid_results, key=lambda r: r['pct']) if valid_results else None
inv = dict(required_scripts=[str(p) for p in required], seeds=seeds, result_sources=results[:200], best_discovered_result=best_result, baseline_input_pct=float("{input.baselinePct}"))
(root / 'inventory.json').write_text(json.dumps(inv, indent=2, sort_keys=True))
with open(log, 'a') as lf:
    lf.write(json.dumps(dict(event='inspect_complete', seed_count=len(seeds), best_discovered_result=best_result)) + '\n')
print(json.dumps(dict(seed_count=len(seeds), best_seed=seeds[0], best_discovered_result=best_result), indent=2))
PY

set -euo pipefail
uv run python - <<'PY'
import json, re
from pathlib import Path
allow = str("{input.allowTraining}").lower() in ('1','true','yes','y')
workflow = json.loads(Path('.pi/workflows/parallelogram-verifier-only-search.json').read_text())
commands = []
def walk(x, path=''):
    if isinstance(x, dict):
        for k, v in x.items():
            if k == 'command' and isinstance(v, str):
                commands.append((path + '.command', v))
            else:
                walk(v, path + '.' + k)
    elif isinstance(x, list):
        for i, v in enumerate(x):
            walk(v, path + '[' + str(i) + ']')
walk(workflow)
terms = ['train' + '_batched' + '_ensemble' + '.py', 'ma' + 'in.py', 'run' + '_pipeline' + '.py', 'slurm/' + 'train', 'sbatch' + ' ' + 'slurm/' + 'train']
violations = []
for path, cmd in commands:
    for term in terms:
        if term in cmd:
            if 'no_training_command_gate' in cmd and path.endswith('.command'):
                continue
            violations.append(dict(path=path, term=term))
if violations and not allow:
    raise SystemExit('training invocation found while allowTraining=false: ' + json.dumps(violations))
print(json.dumps(dict(allowTraining=allow, checked_commands=len(commands), violations=violations)))
PY
